use std::{
    fs,
    path::{Path, PathBuf},
    process::Command,
    time::Instant,
};

use serde::{Deserialize, Serialize};

use crate::{
    fixtures::{create_synthetic_fixture, SyntheticFixtureConfig},
    Result,
};

/// Configuration for the CLI macrobenchmark runner.
#[derive(Debug, Clone, PartialEq)]
pub struct MacrobenchConfig {
    /// Synthetic fixture configuration.
    pub synthetic: SyntheticFixtureConfig,
    /// Patch size passed to `medkit sample` and `medkit bench`.
    pub patch_size: [usize; 3],
    /// Number of patch records generated by `medkit sample`.
    pub samples: usize,
    /// Worker count passed to `medkit bench`.
    pub workers: usize,
    /// Explicit `medkit` binary path. If unset, the runner tries common target paths.
    pub medkit_bin: Option<PathBuf>,
    /// Optional JSON report output path.
    pub out_path: Option<PathBuf>,
}

impl MacrobenchConfig {
    /// Creates a macrobenchmark config with benchmark-friendly defaults.
    pub fn new(root: impl Into<PathBuf>) -> Self {
        Self {
            synthetic: SyntheticFixtureConfig::new(root),
            patch_size: [32, 32, 32],
            samples: 256,
            workers: 4,
            medkit_bin: None,
            out_path: None,
        }
    }
}

/// JSON report produced by the CLI macrobenchmark runner.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct MacrobenchReport {
    /// Synthetic fixture root.
    pub root: String,
    /// Number of generated synthetic cases.
    pub cases: usize,
    /// Source shape in x, y, z order.
    pub shape: [usize; 3],
    /// Cache transform pad/crop shape.
    pub cache_shape: [usize; 3],
    /// Patch size in x, y, z order.
    pub patch_size: [usize; 3],
    /// Patch records emitted by `medkit sample`.
    pub samples: usize,
    /// Worker count passed to `medkit bench`.
    pub workers: usize,
    /// `medkit` binary used.
    pub medkit_bin: String,
    /// Validation stage.
    pub validate: StageReport,
    /// Cache preparation stage.
    pub prepare: StageReport,
    /// Sampling stage.
    pub sample: StageReport,
    /// Built-in medkit benchmark stage.
    pub bench: StageReport,
}

/// Per-stage command timing and output.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct StageReport {
    /// Stage name.
    pub name: String,
    /// Command line.
    pub command: Vec<String>,
    /// Elapsed wall time in milliseconds.
    pub elapsed_ms: f64,
    /// Process exit code.
    pub exit_code: i32,
    /// Captured stdout.
    pub stdout: String,
    /// Captured stderr.
    pub stderr: String,
}

/// Runs the full CLI macrobenchmark against a synthetic fixture.
pub fn run_cli_macrobench(config: &MacrobenchConfig) -> Result<MacrobenchReport> {
    if config.samples == 0 {
        return Err("samples must be greater than zero".into());
    }
    if config.workers == 0 {
        return Err("workers must be greater than zero".into());
    }
    if config.patch_size.contains(&0) {
        return Err(format!("patch size must be non-zero, got {:?}", config.patch_size).into());
    }

    let fixture = create_synthetic_fixture(&config.synthetic)?;
    let medkit_bin = resolve_medkit_bin(config.medkit_bin.as_deref());
    let medkit_bin_string = medkit_bin.to_string_lossy().into_owned();
    let patch = format_patch(config.patch_size);

    let validate = run_stage(
        "validate",
        &medkit_bin,
        &[
            "dataset",
            "validate",
            &fixture.root.to_string_lossy(),
            "--out",
            &fixture.manifest_path.to_string_lossy(),
            "--report",
            &fixture.report_path.to_string_lossy(),
        ],
    )?;

    let prepare = run_stage(
        "prepare",
        &medkit_bin,
        &[
            "prepare",
            &fixture.root.to_string_lossy(),
            "--manifest",
            &fixture.manifest_path.to_string_lossy(),
            "--plan",
            &fixture.plan_path.to_string_lossy(),
            "--cache",
            &fixture.cache_dir.to_string_lossy(),
        ],
    )?;

    let patches_path = fixture.root.join("patches.jsonl");
    let sample_count = config.samples.to_string();
    let sample = run_stage(
        "sample",
        &medkit_bin,
        &[
            "sample",
            &fixture.cache_dir.to_string_lossy(),
            "--patch",
            &patch,
            "--strategy",
            "foreground-balanced",
            "--count",
            &sample_count,
            "--out",
            &patches_path.to_string_lossy(),
        ],
    )?;

    let workers = config.workers.to_string();
    let bench = run_stage(
        "bench",
        &medkit_bin,
        &[
            "bench",
            &fixture.cache_dir.to_string_lossy(),
            "--patch",
            &patch,
            "--workers",
            &workers,
            "--samples",
            &sample_count,
        ],
    )?;

    let report = MacrobenchReport {
        root: fixture.root.to_string_lossy().into_owned(),
        cases: config.synthetic.cases,
        shape: config.synthetic.shape,
        cache_shape: config.synthetic.cache_shape,
        patch_size: config.patch_size,
        samples: config.samples,
        workers: config.workers,
        medkit_bin: medkit_bin_string,
        validate,
        prepare,
        sample,
        bench,
    };
    if let Some(out_path) = &config.out_path {
        if let Some(parent) = out_path.parent() {
            if !parent.as_os_str().is_empty() {
                fs::create_dir_all(parent)?;
            }
        }
        fs::write(out_path, serde_json::to_string_pretty(&report)?)?;
    }
    Ok(report)
}

fn run_stage(name: &str, program: &Path, args: &[&str]) -> Result<StageReport> {
    let mut command = Vec::with_capacity(args.len() + 1);
    command.push(program.to_string_lossy().into_owned());
    command.extend(args.iter().map(|arg| (*arg).to_string()));

    let start = Instant::now();
    let output = Command::new(program).args(args).output()?;
    let elapsed_ms = start.elapsed().as_secs_f64() * 1000.0;
    let exit_code = output.status.code().unwrap_or(-1);
    let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
    let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
    let report = StageReport {
        name: name.to_string(),
        command,
        elapsed_ms,
        exit_code,
        stdout,
        stderr,
    };
    if exit_code != 0 {
        return Err(format!(
            "macrobenchmark stage {name} failed with exit code {exit_code}\nstdout:\n{}\nstderr:\n{}",
            report.stdout, report.stderr
        )
        .into());
    }
    Ok(report)
}

fn resolve_medkit_bin(explicit: Option<&Path>) -> PathBuf {
    if let Some(path) = explicit {
        return path.to_path_buf();
    }
    if let Some(path) = std::env::var_os("MEDKIT_BIN") {
        return PathBuf::from(path);
    }
    if let Ok(current_exe) = std::env::current_exe() {
        if let Some(dir) = current_exe.parent() {
            let sibling = dir.join("medkit");
            if sibling.exists() {
                return sibling;
            }
        }
    }
    PathBuf::from("target").join("debug").join("medkit")
}

fn format_patch(patch_size: [usize; 3]) -> String {
    format!("{},{},{}", patch_size[0], patch_size[1], patch_size[2])
}
